static void NullifyInvalidKeyMaps(Vector &result, idx_t count) {
	auto &keys = MapVector::GetKeys(result);
	auto key_validity = keys.Validity(ListVector::GetListSize(result));

	if (result.GetVectorType() == VectorType::CONSTANT_VECTOR) {
		if (ConstantVector::IsNull(result)) {
			return;
		}
		auto list = ConstantVector::GetData<list_entry_t>(result)[0];
		for (idx_t list_idx = 0; list_idx < list.length; list_idx++) {
			if (!key_validity.IsValid(list.offset + list_idx)) {
				ConstantVector::SetNull(result);
				return;
			}
		}
		return;
	}

	result.Flatten(count);
	auto list_data = FlatVector::GetData<list_entry_t>(result);
	auto &result_validity = FlatVector::ValidityMutable(result);
	for (idx_t row_idx = 0; row_idx < count; row_idx++) {
		if (!result_validity.RowIsValid(row_idx)) {
			continue;
		}
		auto list = list_data[row_idx];
		for (idx_t list_idx = 0; list_idx < list.length; list_idx++) {
			if (!key_validity.IsValid(list.offset + list_idx)) {
				result_validity.SetInvalid(row_idx);
				break;
			}
		}
	}
}

static bool MapToMapCast(Vector &source, Vector &result, idx_t count, CastParameters &parameters) {
	auto all_converted = ListCast::ListToListCast(source, result, count, parameters);
	if (!all_converted && parameters.error_message) {
		NullifyInvalidKeyMaps(result, count);
	}
	MapVector::MapConversionVerify(result, count);
	return all_converted;
}

